// Берём ответ Polza/OpenAI-compatible если есть, иначе fallback
const chatId = $("Normalize Input").item.json.chat_id;
let text = "";
try {
  const j = $json;
  // OpenAI-compatible shape
  const c1 = j && j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content;
  if (typeof c1 === 'string' && c1.trim()) text = c1.trim();
  // Legacy Ollama shape (на случай если кто-то вернёт старый формат)
  if (!text) {
    const c2 = j && j.message && j.message.content;
    if (typeof c2 === 'string' && c2.trim()) text = c2.trim();
  }
} catch (e) {}
if (!text) {
  text = 'Бот получил сообщение, но AI-модуль временно не подключен.';
}
return [{ json: { chat_id: chatId, text } }];

// ── Inputs ────────────────────────────────────────────────────────────────
const apts = $('Load Apartments').all().map(i => i.json);
const bks  = $('Load Bookings Window').all().map(i => i.json);
const gaps = $('Load Gap Windows').all().map(i => i.json);
const recs = $('Load Pricing Recs').all().map(i => i.json);
const competitorRows = $('Load Competitor Sources').all().map(i => i.json);
const msg  = $('Normalize Input').first().json.text || '';

// ── Bookings ────────────────────────────────────────────────────────────────
let booksText = 'БРОНИРОВАНИЯ (ближайшие 60 дней):\n';
if (bks.length === 0) {
  booksText += '  Нет броней в ближайшие 60 дней.\n';
} else {
  for (const b of bks) {
    booksText += `  • Апарт ${b.apartment_id}: ${b.checkin_at?.slice(0,10)} → ${b.checkout_at?.slice(0,10)} (${b.guests_name || 'гость'}, ${b.status})\n`;
  }
}

// ── Apartments ──────────────────────────────────────────────────────────────
let aptsText = 'АПАРТАМЕНТЫ:\n';
for (const a of apts) {
  aptsText += `  • ID ${a.id}: ${a.name || 'Апарт '+a.id}, базовая цена=${a.base_price || '?'} ₽/сут\n`;
}

// ── Gap Windows ──────────────────────────────────────────────────────────────
let gapsText = 'МАЛЕНЬКИЕ ОКНА / GAP WINDOWS (1–3 ночи между бронями):\n';
const openGaps = gaps.filter(g => g.status === 'open');
if (openGaps.length === 0) {
  gapsText += '  Маленьких окон сейчас не найдено.\n';
} else {
  for (const g of openGaps) {
    gapsText += `  • Апарт ${g.apartment_id}: ${g.gap_start} → ${g.gap_end} (${g.nights}н) — ${g.recommendation || ''}`;
    if (g.estimated_loss) gapsText += `, потеря ~${Math.round(g.estimated_loss)} ₽`;
    gapsText += '\n';
  }
}

// ── Pricing Recommendations ───────────────────────────────────────────────────
let recsText = 'ЦЕНОВЫЕ РЕКОМЕНДАЦИИ (C1/C1.5):\n';
const draftRecs = recs.filter(r => r.status === 'draft' || r.status === 'approved');
if (draftRecs.length === 0) {
  recsText += '  Рекомендаций пока нет.\n';
} else {
  for (const r of draftRecs) {
    recsText += `  • Апарт ${r.apartment_id} (${r.date_from}→${r.date_to}): ${r.recommendation_type} — рекомендуем ${r.recommended_price} ₽/сут (confidence ${r.confidence?.toFixed ? r.confidence.toFixed(2) : r.confidence})\n`;
    recsText += `    Причина: ${r.reason}\n`;
  }
}
recsText += '  ⚠️ Рекомендации носят advisory-характер. Цены не меняются автоматически.\n';

// ── Competitor Sources (C1.5) ─────────────────────────────────────────────────
let compText = 'ПРЯМЫЕ КОНКУРЕНТЫ / MARKET SOURCES (C1.5):\n';
const activeSources = competitorRows.filter(c => c.status === 'active');
const excludedSources = competitorRows.filter(c => c.status !== 'active');

if (activeSources.length === 0) {
  compText += '  Активных конкурентов не найдено.\n';
} else {
  compText += `  Активных конкурентов: ${activeSources.length}\n`;
  for (const c of activeSources) {
    const priceRange = c.price_low && c.price_high ? `${c.price_low}–${c.price_high} ₽/сут` : 'цена не указана';
    const latestPrice = c.latest_price ? `${Math.round(c.latest_price)} ₽/сут` : 'нет данных';
    const lastObserved = c.last_observed_at ? new Date(c.last_observed_at).toLocaleDateString('ru-RU') : 'никогда';
    const staleWarn = c.is_stale ? ' ⚠️ данные устарели' : '';
    compText += `  • ${c.name} (similarity ${c.similarity_score}%)\n`;
    compText += `    Платформа: ${c.source_platform}, район: ${c.district || '?'}\n`;
    compText += `    Цена сезона: ${priceRange}${staleWarn}\n`;
    compText += `    Последнее наблюдение: ${latestPrice} (${lastObserved})\n`;
  }
}

if (activeSources.length > 0) {
  const prices = activeSources.map(c => c.latest_price).filter(p => p);
  if (prices.length > 0) {
    const sorted = prices.map(p => parseFloat(p)).sort((a,b)=>a-b);
    const median = sorted[Math.floor(sorted.length/2)];
    compText += `  Рыночная медиана по конкурентам: ~${Math.round(median)} ₽/сут\n`;
  }
  const hasStale = activeSources.some(c => c.is_stale);
  if (hasStale) {
    compText += `  ⚠️ Часть данных конкурентов — seed/устаревшие. Рекомендуется ручная проверка.\n`;
  }
}

// ── Final context ─────────────────────────────────────────────────────────────
const context_text = [
  '=== КОНТЕКСТ ДЛЯ ОТВЕТА ВЛАДЕЛЬЦУ ===',
  aptsText,
  booksText,
  gapsText,
  recsText,
  compText,
  '=== КОНЕЦ КОНТЕКСТА ==='
].join('\n');

return [{ json: { context_text, user_message: msg } }];
